@Test
public void testDistanceWithLargeValues() {
    int[] p1 = new int[] { 100000, 200000 };
    int[] p2 = new int[] { 50000, 150000 };
    double distance = EuclideanIntegerPoint.distance(p1, p2);
    double expected = Math.sqrt((long)(50000) * 50000 + (long)(50000) * 50000);
    assertEquals(expected, distance, 1e-9);
}

@Test
public void testDistanceWithIntegerOverflow() {
    int[] p1 = new int[] { Integer.MAX_VALUE, 0 };
    int[] p2 = new int[] { 0, 0 };
    double distance = EuclideanIntegerPoint.distance(p1, p2);
    double expected = Math.sqrt((long)Integer.MAX_VALUE * Integer.MAX_VALUE);
    assertEquals(expected, distance, 1e-9);
}

@Test
public void testDistanceWithNegativeValues() {
    int[] p1 = new int[] { -100000, -200000 };
    int[] p2 = new int[] { 100000, 200000 };
    double distance = EuclideanIntegerPoint.distance(p1, p2);
    double expected = Math.sqrt((long)(200000) * 200000 + (long)(400000) * 400000);
    assertEquals(expected, distance, 1e-9);
}
